+import Foundation
+
+enum RecordingMode: Equatable {
+    case idle
+    case pushToTalk
+    case toggleToTalk
+}
+
+enum HotkeyEffect: Equatable {
+    case start(RecordingMode)
+    case stop
+    case restart(RecordingMode)
+}
+
+enum HotkeyKey: UInt16, Codable, CaseIterable, Hashable {
+    case tab = 48
+    case space = 49
+    case rightCommand = 54
+    case rightOption = 61
+
+    var isModifier: Bool {
+        rawValue >= 54 && rawValue <= 63
+    }
+}
+
+enum HotkeyEventSnapshot: Equatable {
+    case flagsChanged(HotkeyKey)
+    case keyDown(HotkeyKey)
+    case keyUp(HotkeyKey)
+}
+
+enum HotkeyChordError: Error, Equatable {
+    case empty
+}
+
+struct HotkeyChord: Codable, Equatable {
+    private enum CodingKeys: String, CodingKey {
+        case keyCodes
+    }
+
+    let keyCodes: Set<UInt16>
+
+    init(keys: Set<HotkeyKey>) throws {
+        guard !keys.isEmpty else {
+            throw HotkeyChordError.empty
+        }
+
+        keyCodes = Set(keys.map(\.rawValue))
+    }
+
+    var keys: Set<HotkeyKey> {
+        Set(keyCodes.compactMap(HotkeyKey.init(rawValue:)))
+    }
+
+    init(from decoder: any Decoder) throws {
+        let container = try decoder.container(keyedBy: CodingKeys.self)
+        let codes = try container.decode(Set<UInt16>.self, forKey: .keyCodes)
+        guard !codes.isEmpty else {
+            throw HotkeyChordError.empty
+        }
+        keyCodes = codes
+    }
+}
+
+struct HotkeyBindings: Equatable {
+    var pushToTalk: HotkeyChord
+    var toggleToTalk: HotkeyChord
+
+    static let defaultBindings = HotkeyBindings(
+        pushToTalk: try! HotkeyChord(keys: [.rightCommand, .rightOption]),
+        toggleToTalk: try! HotkeyChord(keys: [.rightCommand, .rightOption, .space])
+    )
+}
+
+final class HotkeyEngine {
+    private(set) var pressedKeys: Set<HotkeyKey> = []
+    private(set) var activeMode: RecordingMode = .idle
+
+    var bindings: HotkeyBindings
+
+    init(bindings: HotkeyBindings) {
+        self.bindings = bindings
+    }
+
+    func process(_ snapshot: HotkeyEventSnapshot) -> [HotkeyEffect] {
+        let priorKeys = pressedKeys
+
+        switch snapshot {
+        case let .flagsChanged(key):
+            if pressedKeys.contains(key) {
+                pressedKeys.remove(key)
+            } else {
+                pressedKeys.insert(key)
+            }
+        case let .keyDown(key):
+            pressedKeys.insert(key)
+        case let .keyUp(key):
+            pressedKeys.remove(key)
+        }
+
+        guard priorKeys != pressedKeys else {
+            return []
+        }
+
+        let match = currentMatch()
+
+        switch activeMode {
+        case .idle:
+            switch match {
+            case .exact(.idle):
+                return []
+            case .exact(.pushToTalk):
+                activeMode = .pushToTalk
+                return [.start(.pushToTalk)]
+            case .exact(.toggleToTalk):
+                activeMode = .toggleToTalk
+                return [.start(.toggleToTalk)]
+            case .prefix, .none:
+                return []
+            }
+        case .pushToTalk:
+            if match == .exact(.toggleToTalk) {
+                activeMode = .toggleToTalk
+                return [.restart(.toggleToTalk)]
+            }
+
+            if !bindings.pushToTalk.keys.isSubset(of: pressedKeys) {
+                activeMode = .idle
+                return [.stop]
+            }
+
+            return []
+        case .toggleToTalk:
+            if match == .exact(.toggleToTalk) {
+                activeMode = .idle
+                return [.stop]
+            }
+
+            return []
+        }
+    }
+
+    private func currentMatch() -> MatchResult {
+        guard !pressedKeys.isEmpty else {
+            return .none
+        }
+
+        if pressedKeys == bindings.pushToTalk.keys {
+            return .exact(.pushToTalk)
+        }
+
+        if pressedKeys == bindings.toggleToTalk.keys {
+            return .exact(.toggleToTalk)
+        }
+
+        if pressedKeys.isStrictSubset(of: bindings.pushToTalk.keys) || pressedKeys.isStrictSubset(of: bindings.toggleToTalk.keys) {
+            return .prefix
+        }
+
+        return .none
+    }
+}
+
+private enum MatchResult: Equatable {
+    case exact(RecordingMode)
+    case prefix
+    case none
+}

