+import Foundation
+
+enum PipelineOwner: Equatable {
+    case liveRecording
+    case transcriptionLab
+}
+
+final class PipelineGate {
+    private(set) var currentOwner: PipelineOwner?
+
+    func acquire(_ owner: PipelineOwner) -> Bool {
+        guard currentOwner == nil else {
+            return false
+        }
+
+        currentOwner = owner
+        return true
+    }
+
+    func release(_ owner: PipelineOwner) {
+        guard currentOwner == owner else {
+            return
+        }
+
+        currentOwner = nil
+    }
+}

