+import Foundation
+import Observation
+
+@Observable
+final class SettingsStore {
+    private enum Keys {
+        static let cleanupEnabled = "cleanupEnabled"
+        static let speechModel = "speechModel"
+        static let cleanupBackend = "cleanupBackend"
+        static let frontmostWindowContextEnabled = "frontmostWindowContextEnabled"
+        static let postPasteLearningEnabled = "postPasteLearningEnabled"
+        static let ignoreOtherSpeakers = "ignoreOtherSpeakers"
+        static let playSounds = "playSounds"
+        static let selectedCleanupModelKind = "selectedCleanupModelKind"
+        static let pushToTalkChord = "chordBinding.pushToTalk"
+        static let toggleToTalkChord = "chordBinding.toggleToTalk"
+    }
+
+    private let userDefaults: UserDefaults
+    private let encoder = JSONEncoder()
+    private let decoder = JSONDecoder()
+
+    var cleanupEnabled: Bool {
+        didSet { userDefaults.set(cleanupEnabled, forKey: Keys.cleanupEnabled) }
+    }
+
+    var speechModelID: String {
+        didSet { userDefaults.set(speechModelID, forKey: Keys.speechModel) }
+    }
+
+    var cleanupBackend: String {
+        didSet { userDefaults.set(cleanupBackend, forKey: Keys.cleanupBackend) }
+    }
+
+    var frontmostWindowContextEnabled: Bool {
+        didSet { userDefaults.set(frontmostWindowContextEnabled, forKey: Keys.frontmostWindowContextEnabled) }
+    }
+
+    var postPasteLearningEnabled: Bool {
+        didSet { userDefaults.set(postPasteLearningEnabled, forKey: Keys.postPasteLearningEnabled) }
+    }
+
+    var ignoreOtherSpeakers: Bool {
+        didSet { userDefaults.set(ignoreOtherSpeakers, forKey: Keys.ignoreOtherSpeakers) }
+    }
+
+    var playSounds: Bool {
+        didSet { userDefaults.set(playSounds, forKey: Keys.playSounds) }
+    }
+
+    var selectedCleanupModelKind: String {
+        didSet { userDefaults.set(selectedCleanupModelKind, forKey: Keys.selectedCleanupModelKind) }
+    }
+
+    private(set) var pushToTalkChord: HotkeyChord {
+        didSet { persist(pushToTalkChord, forKey: Keys.pushToTalkChord) }
+    }
+
+    private(set) var toggleToTalkChord: HotkeyChord {
+        didSet { persist(toggleToTalkChord, forKey: Keys.toggleToTalkChord) }
+    }
+
+    init(userDefaults: UserDefaults = .standard) {
+        self.userDefaults = userDefaults
+
+        cleanupEnabled = userDefaults.object(forKey: Keys.cleanupEnabled) as? Bool ?? true
+        speechModelID = userDefaults.string(forKey: Keys.speechModel) ?? "openai_whisper-small.en"
+        cleanupBackend = userDefaults.string(forKey: Keys.cleanupBackend) ?? "localModels"
+        frontmostWindowContextEnabled = userDefaults.object(forKey: Keys.frontmostWindowContextEnabled) as? Bool ?? false
+        postPasteLearningEnabled = userDefaults.object(forKey: Keys.postPasteLearningEnabled) as? Bool ?? true
+        ignoreOtherSpeakers = userDefaults.object(forKey: Keys.ignoreOtherSpeakers) as? Bool ?? false
+        playSounds = userDefaults.object(forKey: Keys.playSounds) as? Bool ?? true
+        selectedCleanupModelKind = userDefaults.string(forKey: Keys.selectedCleanupModelKind) ?? "qwen35_0_8b_q4_k_m"
+        pushToTalkChord = SettingsStore.decodeChord(from: userDefaults.data(forKey: Keys.pushToTalkChord)) ?? HotkeyBindings.defaultBindings.pushToTalk
+        toggleToTalkChord = SettingsStore.decodeChord(from: userDefaults.data(forKey: Keys.toggleToTalkChord)) ?? HotkeyBindings.defaultBindings.toggleToTalk
+
+        userDefaults.set(cleanupEnabled, forKey: Keys.cleanupEnabled)
+        userDefaults.set(speechModelID, forKey: Keys.speechModel)
+        userDefaults.set(cleanupBackend, forKey: Keys.cleanupBackend)
+        userDefaults.set(frontmostWindowContextEnabled, forKey: Keys.frontmostWindowContextEnabled)
+        userDefaults.set(postPasteLearningEnabled, forKey: Keys.postPasteLearningEnabled)
+        userDefaults.set(ignoreOtherSpeakers, forKey: Keys.ignoreOtherSpeakers)
+        userDefaults.set(playSounds, forKey: Keys.playSounds)
+        userDefaults.set(selectedCleanupModelKind, forKey: Keys.selectedCleanupModelKind)
+        persist(pushToTalkChord, forKey: Keys.pushToTalkChord)
+        persist(toggleToTalkChord, forKey: Keys.toggleToTalkChord)
+    }
+
+    private func persist(_ chord: HotkeyChord, forKey key: String) {
+        if let data = try? encoder.encode(chord) {
+            userDefaults.set(data, forKey: key)
+        }
+    }
+
+    private static func decodeChord(from data: Data?) -> HotkeyChord? {
+        guard let data else {
+            return nil
+        }
+
+        return try? JSONDecoder().decode(HotkeyChord.self, from: data)
+    }
+}
